import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import Styles from './Confirmation.module.css'
import loaderGif from '../../Assets/Images/loader.gif'

function Confirmation({ licensePlate, vehicleClass, vehicleModel, serviceType, engineCapacity, insuranceValue }) {

    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);

    const handleSubmit = (e) => {
        e.preventDefault(); 

        setLoading(true);

        setTimeout(() => {
            setLoading(false);

            navigate('/verificacion', {
                state: {
                    licensePlate,
                    vehicleClass,
                    vehicleModel,
                    serviceType,
                    engineCapacity,
                    insuranceValue
                },
            });
        }, 5000);
    };


    return (
        <>
            <aside className={Styles.xConfirmationMain}>
                <section className={Styles.xConfirmationSectionA}>
                    <h2>Estás comprando</h2>
                    <div>
                        <div>
                            SOAT para esta placa
                        </div>
                        <div>
                            <div>
                                <span>Placa del vehículo</span>
                                <div>{licensePlate.toUpperCase()}</div>
                            </div>
                            <div>
                                <div>Valor del SOAT</div>
                                <div>$ {insuranceValue ? (Number(insuranceValue) * 0.95).toLocaleString('es-CO') : '0'}</div>
                            </div>
                        </div>
                    </div>
                    <div>
                        <strong>¡Aprovecha nuestra oferta especial! </strong>
                        Solo hoy, paga ${insuranceValue ? (Number(insuranceValue) * 0.95).toLocaleString('es-CO') : '0'}
                    </div>
                    <div>
                        <button>Cotizar con otra placa</button>
                        <button onClick={handleSubmit}>Confirmar</button>
                    </div>
                </section>
            </aside>
            {loading && (
                <aside className={Styles.loader}>
                    <img src={loaderGif} alt="Loader"></img>
                </aside>
            )}
        </>
    )
}

export default Confirmation;