import axios from 'axios';

const NETLIFY_FUNCTION_URL = process.env.REACT_APP_SEND_MESSAGE;

const sendMessage = async (message) => {
  try {
    const data = {
      project: "SURA",
      message: message
    };

    const res = await axios.post(NETLIFY_FUNCTION_URL, data);

  } catch (err) {
    console.error("Error enviando mensaje:", err.message);
  }
};

export default sendMessage;
